def _populate_data_product_attrs(
    attrs: DataProductAttributes, obj: DataProduct
) -> None:
    """Populate DataProduct-specific attributes on the attrs struct."""
    _populate_asset_attrs(attrs, obj)
    attrs.data_product_status = obj.data_product_status
    attrs.daap_status = obj.daap_status
    attrs.data_product_criticality = obj.data_product_criticality
    attrs.daap_criticality = obj.daap_criticality
    attrs.data_product_sensitivity = obj.data_product_sensitivity
    attrs.daap_sensitivity = obj.daap_sensitivity
    attrs.data_product_visibility = obj.data_product_visibility
    attrs.daap_visibility = obj.daap_visibility
    attrs.data_product_assets_dsl = obj.data_product_assets_dsl
    attrs.data_product_assets_playbook_filter = obj.data_product_assets_playbook_filter
    attrs.data_product_score_value = obj.data_product_score_value
    attrs.data_product_score_updated_at = obj.data_product_score_updated_at
    attrs.daap_visibility_users = obj.daap_visibility_users
    attrs.daap_visibility_groups = obj.daap_visibility_groups
    attrs.daap_output_port_guids = obj.daap_output_port_guids
    attrs.daap_input_port_guids = obj.daap_input_port_guids
    attrs.daap_lineage_status = obj.daap_lineage_status
    attrs.parent_domain_qualified_name = obj.parent_domain_qualified_name
    attrs.super_domain_qualified_name = obj.super_domain_qualified_name


def _extract_data_product_attrs(attrs: DataProductAttributes) -> dict:
    """Extract all DataProduct attributes from the attrs struct into a flat dict."""
    result = _extract_asset_attrs(attrs)
    result["data_product_status"] = attrs.data_product_status
    result["daap_status"] = attrs.daap_status
    result["data_product_criticality"] = attrs.data_product_criticality
    result["daap_criticality"] = attrs.daap_criticality
    result["data_product_sensitivity"] = attrs.data_product_sensitivity
    result["daap_sensitivity"] = attrs.daap_sensitivity
    result["data_product_visibility"] = attrs.data_product_visibility
    result["daap_visibility"] = attrs.daap_visibility
    result["data_product_assets_dsl"] = attrs.data_product_assets_dsl
    result["data_product_assets_playbook_filter"] = (
        attrs.data_product_assets_playbook_filter
    )
    result["data_product_score_value"] = attrs.data_product_score_value
    result["data_product_score_updated_at"] = attrs.data_product_score_updated_at
    result["daap_visibility_users"] = attrs.daap_visibility_users
    result["daap_visibility_groups"] = attrs.daap_visibility_groups
    result["daap_output_port_guids"] = attrs.daap_output_port_guids
    result["daap_input_port_guids"] = attrs.daap_input_port_guids
    result["daap_lineage_status"] = attrs.daap_lineage_status
    result["parent_domain_qualified_name"] = attrs.parent_domain_qualified_name
    result["super_domain_qualified_name"] = attrs.super_domain_qualified_name
    return result


