def _data_product_to_nested(data_product: DataProduct) -> DataProductNested:
    """Convert flat DataProduct to nested format."""
    attrs = DataProductAttributes()
    _populate_data_product_attrs(attrs, data_product)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        data_product, _DATA_PRODUCT_REL_FIELDS, DataProductRelationshipAttributes
    )
    return DataProductNested(
        guid=data_product.guid,
        type_name=data_product.type_name,
        status=data_product.status,
        version=data_product.version,
        create_time=data_product.create_time,
        update_time=data_product.update_time,
        created_by=data_product.created_by,
        updated_by=data_product.updated_by,
        classifications=data_product.classifications,
        classification_names=data_product.classification_names,
        meanings=data_product.meanings,
        labels=data_product.labels,
        business_attributes=data_product.business_attributes,
        custom_attributes=data_product.custom_attributes,
        pending_tasks=data_product.pending_tasks,
        proxy=data_product.proxy,
        is_incomplete=data_product.is_incomplete,
        provenance_type=data_product.provenance_type,
        home_id=data_product.home_id,
        depth=data_product.depth,
        immediate_upstream=data_product.immediate_upstream,
        immediate_downstream=data_product.immediate_downstream,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _data_product_from_nested(nested: DataProductNested) -> DataProduct:
    """Convert nested format to flat DataProduct."""
    attrs = (
        nested.attributes if nested.attributes is not UNSET else DataProductAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _DATA_PRODUCT_REL_FIELDS,
        DataProductRelationshipAttributes,
    )
    return DataProduct(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        depth=nested.depth,
        immediate_upstream=nested.immediate_upstream,
        immediate_downstream=nested.immediate_downstream,
        **_extract_data_product_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _data_product_to_nested_bytes(data_product: DataProduct, serde: Serde) -> bytes:
    """Convert flat DataProduct to nested JSON bytes."""
    return serde.encode(_data_product_to_nested(data_product))


def _data_product_from_nested_bytes(data: bytes, serde: Serde) -> DataProduct:
    """Convert nested JSON bytes to flat DataProduct."""
    nested = serde.decode(data, DataProductNested)
    return _data_product_from_nested(nested)


